import React from 'react';
import merge from 'classnames';

import { Button, Image, Input, SearchIcon, CrossIcon } from 'components';

import { Hamburger } from './components';
import { State } from './Header.types';
import styles from './Header.module.scss';

export class Header extends React.Component<{}, State> {
  state: State = {
    isMenuOpened: false,
    isSearchInputFocused: false,
    searchValue: '',
  };

  searchInput: HTMLInputElement | null = null;

  // Component lifecycle methods

  componentDidMount() {
    document.addEventListener('keydown', this.handleKeyboardEvent);
  }

  componentDidUpdate() {
    const { isMenuOpened, isSearchInputFocused } = this.state;

    document.getElementById('root')!.classList[isMenuOpened ? 'add' : 'remove']('no-scroll');
    isSearchInputFocused ? this.searchInput!.focus() : this.searchInput!.blur();
  }

  // Helper functions

  isEscapeButtonPressed = (event: KeyboardEvent): boolean => {
    return event.keyCode === 27 && event.code === 'Escape' && event.key === 'Escape';
  };

  // Action handlers

  setSearchInputReference = (element: HTMLInputElement): void => {
    this.searchInput = element;
  };

  openMobileMenu = (): void => {
    this.setState({ isMenuOpened: true });
  };

  closeMobileMenu = (): void => {
    this.setState({ isMenuOpened: false });
  };

  handleKeyboardEvent = (event: KeyboardEvent): void => {
    if (this.isEscapeButtonPressed(event)) {
      const { isMenuOpened, isSearchInputFocused } = this.state;

      switch (true) {
        case isMenuOpened:
          this.closeMobileMenu();
          break;

        case isSearchInputFocused:
          this.onSearchInputBlur();
          break;
      }
    }
  };

  // Event handlers

  onLogoClick = (): void => {
    console.log('redirect to "Home" page');
  };

  onLoginButtonClick = (): void => {
    this.closeMobileMenu();
    console.log('login user');
  };

  onSearchIconClick = (): void => {
    this.searchInput!.focus();
  };

  onCrossIconClick = (): void => {
    this.setState({ searchValue: '', isSearchInputFocused: false });
  };

  onSearchValueChange = (event: React.ChangeEvent<HTMLInputElement>): void => {
    this.setState({ searchValue: event.target.value });
  };

  onSearchInputFocus = (): void => {
    this.setState({ isSearchInputFocused: true });
  };

  onSearchInputBlur = (): void => {
    this.setState({ isSearchInputFocused: false });
  };

  // RENDER

  render() {
    const { isMenuOpened, isSearchInputFocused, searchValue } = this.state;

    return (
      <header className={styles.header}>
        <div className={styles.left}>
          <div className={styles.title} onClick={this.onLogoClick}>
            <Image
              src="images/application_logo.png"
              alt="Poku Art Challenge logo"
              pixelRatio={2}
              className={styles.logo}
            />

            <span>Poku Art Challenge</span>
          </div>

          <div className={styles.search}>
            <SearchIcon className={styles.small_search_icon} color="white" />

            <Input
              type="text"
              color="green"
              placeholder="search"
              value={searchValue}
              className={merge(styles.input, { [styles.opened]: searchValue })}
              innerRef={this.setSearchInputReference}
              onChange={this.onSearchValueChange}
              onFocus={this.onSearchInputFocus}
              onBlur={this.onSearchInputBlur}
            />

            {isSearchInputFocused || searchValue ? (
              <CrossIcon
                onClick={this.onCrossIconClick}
                className={styles.cross_icon}
                color="white"
              />
            ) : (
              <SearchIcon
                onClick={this.onSearchIconClick}
                className={styles.search_icon}
                color="white"
              />
            )}
          </div>
        </div>

        <div className={styles.right}>
          <nav className={merge(styles.nav, { [styles.nav_opened]: isMenuOpened })}>
            <div className={styles.nav_header}>
              <span>Guest</span>
              <Hamburger active={true} onClick={this.closeMobileMenu} />
            </div>

            <Button color="transparent" onClick={this.onLoginButtonClick} className={styles.button}>
              Log In
            </Button>
          </nav>

          <div
            className={merge(styles.nav_backdrop, { [styles.nav_opened]: isMenuOpened })}
            onClick={this.closeMobileMenu}
          />

          <Hamburger active={false} onClick={this.openMobileMenu} />
        </div>
      </header>
    );
  }
}
